#include <bits/stdc++.h>
using namespace std;
const int maxn=5e3+5,mod=1e8;
int n,f[2][maxn],num[2][maxn];
string a,b;
int lena,lenb;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>a>>b;
	lena=a.size()-1;
	lenb=b.size()-1;
	for(int i=0;i<=lenb;i++){
		num[0][i]=1;
	}
	num[1][0]=1;
	for(int i=1; i<=lena; i++) {
		for(int j=1; j<=lenb; j++) {
			if(a[i-1]==b[j-1]) {
				f[1][j]=f[0][j-1]+1;
				num[1][j]=(0ll+num[0][j-1]+num[1][j])%mod;
			} else {
				f[1][j]=max(f[0][j],f[1][j-1]);
			}
			if(f[1][j]==f[0][j]){
				num[1][j]=(0ll+num[0][j]+num[1][j])%mod;
			}
			if(f[1][j]==f[1][j-1]){
				num[1][j]=(0ll+num[1][j]+num[1][j-1])%mod;
			}
			if(a[i-1]!=b[j-1]&&f[1][j]==f[0][j-1]){
				num[1][j]=(0ll+num[1][j]-num[0][j-1]+mod)%mod;
			}
		}
		for(int j=1;j<=lenb;j++){
			f[0][j]=f[1][j];
			f[1][j]=0;
			num[0][j]=num[1][j];
			num[1][j]=0;
		}
	}
	cout<<f[0][lenb]<<"\n"<<num[0][lenb];
	return 0;
}
